"""
MABE Bootstrap: 6PPD-Quinone Integration

Adds small-molecule guest design pipeline to MABE:
  SMILES → pharmacophore → pocket spec → host screening → MIP design → de novo receptors

New modules:
  core/small_molecule_target.py   — Guest pharmacophore → InteractionGeometrySpec + host screening
  adapters/mip_adapter.py         — MIP monomer selection, formulation, synthesis protocol
  tests/test_6ppd_q.py            — 44 integration tests for 6PPD-Q test case

Modified modules:
  core/physics_realization_bridge.py — +design_for_guest() entry point, +GuestDesignResult
  core/de_novo_generator.py          — +16 receptor backbones, +generate_for_guest(),
                                       +pharmacophore-driven arm selection, +complementarity scoring

Test results: 44 passed (6PPD-Q), 95 passed (regression), 0 failed

Entry point:
  from core.physics_realization_bridge import design_for_guest
  result = design_for_guest("CC(C)CC(NC1=CC(=O)C(=CC1=O)NC2=CC=CC=C2)C",
                            name="6PPD-quinone", application="remediation")

Prereqs: F0-F3 complete (unified_scorer_v2, physics_realization_bridge, hg_scorer)
"""
import base64, pathlib, os

FILES = {
    "core/small_molecule_target.py": "",
    "adapters/mip_adapter.py": "",
    "tests/test_6ppd_q.py": "",
    "core/physics_realization_bridge.py": "",
    "core/de_novo_generator.py": "",
}


def apply():
    root = pathlib.Path(__file__).resolve().parent
    for rel_path, b64_content in FILES.items():
        target = root / rel_path
        target.parent.mkdir(parents=True, exist_ok=True)
        content = base64.b64decode(b64_content)
        target.write_bytes(content)
        print(f"  wrote {rel_path} ({len(content):,} bytes)")
    print(f"\n  {len(FILES)} files written.")


if __name__ == "__main__":
    print("=" * 70)
    print("MABE Bootstrap: 6PPD-Quinone Integration")
    print("=" * 70)
    apply()
    print("\nRun tests:  python -m pytest tests/test_6ppd_q.py -v")